#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    int left = 0, right = n - 1;
    long long max_water = 0;
    while (left < right) {
        int width = right - left;
        int min_height = min(nums[left], nums[right]);
        long long water = (long long)width * min_height;
        max_water = max(max_water, water);
        if (nums[left] < nums[right]) {
            left += 1;
        } else {
            right -= 1;
        }
    }
    cout << max_water << endl;
    return 0;
}
